/// 合并待上报时长对应的 vapp id；如果一轮内混入多个 vapp，则清成冲突态避免归错。
- (void)mergePendingVappId:(NSInteger)vappId {
    if (vappId <= 0) {
        return;
    }
    if (self.pendingVappId == 0) {
        self.pendingVappId = vappId;
        return;
    }
    if (self.pendingVappId > 0 && self.pendingVappId != vappId) {
        self.pendingVappId = -1;
    }
}

/// 结算最近一个前台可观测区间的真实时长，并累计到 a/v。
- (void)accumulateElapsedUsageAtTime:(CFAbsoluteTime)now {
    if (self.lastUsageRecordTime <= 0) {
        self.lastUsageRecordTime = now;
        return;
    }
    // 后台区间会在回前台或终止时统一补算，这里直接跳过，避免重复累计。
    if ([WBEventManager hasBackgroundEnterTime]) {
        self.lastUsageRecordTime = now;
        return;
    }
    CFAbsoluteTime elapsed = now - self.lastUsageRecordTime;
    if (elapsed <= 0) {
        self.lastUsageRecordTime = now;
        return;
    }
    self.appUsedTimeInSecond += elapsed;
    NSInteger currentVappId = [self currentRunningVappId];
    if (currentVappId > 0) {
        [self mergePendingVappId:currentVappId];
        self.vappUsedTimeInSecond += elapsed;
    }
    self.lastUsageRecordTime = now;
}

/// 用进入后台和恢复时的时间点，补算挂起期间的真实时长，并并入下一次 heartbeat。
- (void)applyBackgroundUsageAtTime:(CFAbsoluteTime)now {
    if (![WBEventManager hasBackgroundEnterTime]) {
        self.lastUsageRecordTime = now;
        return;
    }
    // 根据生命周期时间点重建后台挂起区间，并将其并入下一次 heartbeat。
    CFAbsoluteTime backgroundTime = [WBEventManager backgroundEnterTime];
    if (backgroundTime > 0 && now >= backgroundTime) {
        NSTimeInterval backgroundDuration = now - backgroundTime;
        self.appUsedTimeInSecond += backgroundDuration;
        self.backgroundUsedTimeInSecond += backgroundDuration;
        // 只有进入后台时确实有 vapp 在跑，才把后台区间同时累计进 v。
        if ([WBEventManager backgroundHadRunningVapp]) {
            NSInteger backgroundVappId = [WBEventManager backgroundVappId];
            [self mergePendingVappId:backgroundVappId];
            self.vappUsedTimeInSecond += backgroundDuration;
        }
    }
    [WBEventManager clearBackgroundTrackingState];
    self.lastUsageRecordTime = now;
}

