- (void)setBenefitTrialUsageTimes:(NSDictionary<NSString *, NSNumber *> *)BenefitTrialUsageTimes {
    NSString *key = @"DICT_FOR_PROPERTY_BenefitTrialUsageTimes";
    NSString *hashedKey = [WBUtility getCodeNameSaltedSha1Hash:key];
    NSMutableDictionary *toStore = [NSMutableDictionary dictionaryWithCapacity:BenefitTrialUsageTimes.count];
    [BenefitTrialUsageTimes enumerateKeysAndObjectsUsingBlock:^(id k, id obj, BOOL *stop) {
        NSString *stringKey = [k isKindOfClass:NSString.class] ? k : [[k description] copy];
        NSNumber *num = [obj isKindOfClass:NSNumber.class] ? obj : @([[obj description] integerValue]);
        if (stringKey && num) {
            NSInteger iv = [num integerValue];
            if (iv < 0) iv = 0;
            toStore[stringKey] = @(iv);
        }
    }];
    [self.userDefaults setObject:toStore forKey:hashedKey];
}


- (NSInteger)trialUsageTimesForBenefitBit:(NSInteger)bit {
    NSDictionary<NSString *, NSNumber *> *dict = self.BenefitTrialUsageTimes ?: @{};
    NSString *key = [NSString stringWithFormat:@"%ld", (long)bit];
    NSNumber *num = dict[key];
    return [num integerValue];
}

- (void)setTrialUsageTimes:(NSInteger)times forBenefitBit:(NSInteger)bit {
    if (times < 0) times = 0;
    NSMutableDictionary<NSString *, NSNumber *> *dict = [[self BenefitTrialUsageTimes] mutableCopy];
    if (!dict) dict = [NSMutableDictionary dictionary];
    NSString *key = [NSString stringWithFormat:@"%ld", (long)bit];
    dict[key] = @(times);
    self.BenefitTrialUsageTimes = dict;
}

